 &lt;blockquote&gt;
&lt;p&gt;本文介绍了在宝塔系统上基于 MySQL，采用 Docker部署 Waline 的方法，并提供 Github 社交登陆，渐变彩色邮件通知模板！&lt;/p&gt;
&lt;/blockquote&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;
&lt;h2 id=&#34;准备工作&#34;&gt;准备工作&lt;/h2&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;注册一个邮箱，并开启SMTP 。waline 邮件通知需要用到&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;你得有一个vps 。 目前个人能找到的最便宜的 VPS 服务商: &lt;a href=&#34;https://my.racknerd.com/aff.php?aff=3312&#34;&gt;racknerd VPS&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;安装配置好宝塔。 &lt;a href=&#34;/posts/7b4e434c/&#34;&gt;宝塔安装与配置简明教程&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;创建waline-数据库&#34;&gt;创建waline 数据库&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;以 mysql 数据库为例&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/02/21/20230221011317.webp&#34; alt=&#34;创建mysql数据库&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;MySQL-数据库初始化&#34;&gt;MySQL 数据库初始化&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;a href=&#34;https://waline.js.org/guide/database.html#mysql&#34;&gt;https://waline.js.org/guide/database.html#mysql&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://github.com/walinejs/waline/blob/main/assets/waline.sql&#34;&gt;https://github.com/walinejs/waline/blob/main/assets/waline.sql&lt;/a&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-sql&#34; data-language=&#34;sql&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-sql&#34;&gt;&amp;#x2F;*!40101 SET @OLD_CHARACTER_SET_CLIENT&amp;#x3D;@@CHARACTER_SET_CLIENT *&amp;#x2F;;
&amp;#x2F;*!40101 SET @OLD_CHARACTER_SET_RESULTS&amp;#x3D;@@CHARACTER_SET_RESULTS *&amp;#x2F;;
&amp;#x2F;*!40101 SET @OLD_COLLATION_CONNECTION&amp;#x3D;@@COLLATION_CONNECTION *&amp;#x2F;;
&amp;#x2F;*!40101 SET NAMES utf8 *&amp;#x2F;;
SET NAMES utf8mb4;
&amp;#x2F;*!40014 SET @OLD_FOREIGN_KEY_CHECKS&amp;#x3D;@@FOREIGN_KEY_CHECKS, FOREIGN_KEY_CHECKS&amp;#x3D;0 *&amp;#x2F;;
&amp;#x2F;*!40101 SET @OLD_SQL_MODE&amp;#x3D;@@SQL_MODE, SQL_MODE&amp;#x3D;&amp;#39;NO_AUTO_VALUE_ON_ZERO&amp;#39; *&amp;#x2F;;
&amp;#x2F;*!40111 SET @OLD_SQL_NOTES&amp;#x3D;@@SQL_NOTES, SQL_NOTES&amp;#x3D;0 *&amp;#x2F;;


# Dump of table wl_Comment
# ------------------------------------------------------------

CREATE TABLE &amp;#96;wl_Comment&amp;#96; (
  &amp;#96;id&amp;#96; int(11) unsigned NOT NULL AUTO_INCREMENT,
  &amp;#96;user_id&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;comment&amp;#96; text,
  &amp;#96;insertedAt&amp;#96; timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  &amp;#96;ip&amp;#96; varchar(100) DEFAULT &amp;#39;&amp;#39;,
  &amp;#96;link&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;mail&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;nick&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;pid&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;rid&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;sticky&amp;#96; boolean DEFAULT NULL,
  &amp;#96;status&amp;#96; varchar(50) NOT NULL DEFAULT &amp;#39;&amp;#39;,
  &amp;#96;like&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;ua&amp;#96; text,
  &amp;#96;url&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;createdAt&amp;#96; timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  &amp;#96;updatedAt&amp;#96; timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (&amp;#96;id&amp;#96;)
) ENGINE&amp;#x3D;InnoDB DEFAULT CHARSET&amp;#x3D;utf8mb4;



# Dump of table wl_Counter
# ------------------------------------------------------------

CREATE TABLE &amp;#96;wl_Counter&amp;#96; (
  &amp;#96;id&amp;#96; int(11) unsigned NOT NULL AUTO_INCREMENT,
  &amp;#96;time&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;reaction0&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;reaction1&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;reaction2&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;reaction3&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;reaction4&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;reaction5&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;reaction6&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;reaction7&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;reaction8&amp;#96; int(11) DEFAULT NULL,
  &amp;#96;url&amp;#96; varchar(255) NOT NULL DEFAULT &amp;#39;&amp;#39;,
  &amp;#96;createdAt&amp;#96; timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  &amp;#96;updatedAt&amp;#96; timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (&amp;#96;id&amp;#96;)
) ENGINE&amp;#x3D;InnoDB DEFAULT CHARSET&amp;#x3D;utf8mb4;



# Dump of table wl_Users
# ------------------------------------------------------------

CREATE TABLE &amp;#96;wl_Users&amp;#96; (
  &amp;#96;id&amp;#96; int(11) unsigned NOT NULL AUTO_INCREMENT,
  &amp;#96;display_name&amp;#96; varchar(255) NOT NULL DEFAULT &amp;#39;&amp;#39;,
  &amp;#96;email&amp;#96; varchar(255) NOT NULL DEFAULT &amp;#39;&amp;#39;,
  &amp;#96;password&amp;#96; varchar(255) NOT NULL DEFAULT &amp;#39;&amp;#39;,
  &amp;#96;type&amp;#96; varchar(50) NOT NULL DEFAULT &amp;#39;&amp;#39;,
  &amp;#96;label&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;url&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;avatar&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;github&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;twitter&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;facebook&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;google&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;weibo&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;qq&amp;#96; varchar(255) DEFAULT NULL,
  &amp;#96;2fa&amp;#96; varchar(32) DEFAULT NULL,
  &amp;#96;createdAt&amp;#96; timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  &amp;#96;updatedAt&amp;#96; timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (&amp;#96;id&amp;#96;)
) ENGINE&amp;#x3D;InnoDB DEFAULT CHARSET&amp;#x3D;utf8mb4;




&amp;#x2F;*!40111 SET SQL_NOTES&amp;#x3D;@OLD_SQL_NOTES *&amp;#x2F;;
&amp;#x2F;*!40101 SET SQL_MODE&amp;#x3D;@OLD_SQL_MODE *&amp;#x2F;;
&amp;#x2F;*!40014 SET FOREIGN_KEY_CHECKS&amp;#x3D;@OLD_FOREIGN_KEY_CHECKS *&amp;#x2F;;
&amp;#x2F;*!40101 SET CHARACTER_SET_CLIENT&amp;#x3D;@OLD_CHARACTER_SET_CLIENT *&amp;#x2F;;
&amp;#x2F;*!40101 SET CHARACTER_SET_RESULTS&amp;#x3D;@OLD_CHARACTER_SET_RESULTS *&amp;#x2F;;
&amp;#x2F;*!40101 SET COLLATION_CONNECTION&amp;#x3D;@OLD_COLLATION_CONNECTION *&amp;#x2F;;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/02/21/20230221011317-1.webp&#34; alt=&#34;管理数据库&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/02/21/20230221011317-2.webp&#34; alt=&#34;导入sql初始化文件&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/02/21/20230221011317-3.webp&#34; alt=&#34;执行sql初始化文件&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;docker-安装-waline&#34;&gt;docker 安装 waline&lt;/h2&gt;
&lt;h3 id=&#34;vps-yml-文件&#34;&gt;&lt;code&gt;vps.yml&lt;/code&gt; 文件&lt;/h3&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-yaml&#34; data-language=&#34;yaml&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-yaml&#34;&gt;# docker compose文件 

version: &amp;quot;3&amp;quot;
services:
  waline:
    container_name: waline
    image: lizheming&amp;#x2F;waline:latest
    hostname: waline
    restart: always
    volumes:
      - &amp;#x2F;www&amp;#x2F;docker&amp;#x2F;waline&amp;#x2F;data:&amp;#x2F;app&amp;#x2F;data
    network_mode: host
    env_file:
      - .env # 由于单引号和双引号过多，邮件通知模板只能放在这里面
    environment:
      TZ: &amp;#39;Asia&amp;#x2F;Shanghai&amp;#39;

      MYSQL_DB: &amp;#39;waline&amp;#39;
      MYSQL_USER: &amp;#39;waline&amp;#39;
      MYSQL_PASSWORD: &amp;#39;[随机密码]&amp;#39; # 前面创建数据库时生成的随机密码

      SITE_NAME: &amp;#39;夜法之书&amp;#39;
      SITE_URL: &amp;#39;https:&amp;#x2F;&amp;#x2F;blog.17lai.site&amp;#39;
      SECURE_DOMAINS: &amp;#39;blog.17lai.site,blog.17lai.fun&amp;#39;
      AUTHOR_EMAIL: &amp;#39;xxx@gmail.com&amp;#39;

      # 电报通知
      TG_BOT_TOKEN: &amp;#39;xxxxx&amp;#39;
      TG_CHAT_ID: &amp;#39;xxxxx&amp;#39;

      # 邮件通知
      SMTP_SERVICE: &amp;#39;126&amp;#39;
      SMTP_HOST: &amp;#39;smtp.126.com&amp;#39;
      SMTP_PORT: &amp;#39;465&amp;#39;
      SMTP_USER: &amp;#39;xxxxx@126.com&amp;#39;
      SMTP_PASS: &amp;#39;xxxxx&amp;#39;
      SENDER_NAME: &amp;#39;夜法之书&amp;#39;
      SENDER_EMAIL: &amp;#39;xxxxx@126.com&amp;#39;	# 注意这里需要和 SMTP_USER 一致

      AKISMET_KEY: xxxxx	# 反垃圾邮件

      LEVELS: &amp;#39;0,10,20,50,100,200&amp;#39;
      DISABLE_REGION: &amp;#39;true&amp;#39;

      # google RECAPTCHA
      RECAPTCHA_V3_KEY: xxxx
      RECAPTCHA_V3_SECRET: xxxx

      # github 社交登录
      GITHUB_ID: xxxx
      GITHUB_SECRET: xxxx&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;blockquote&gt;
&lt;p&gt;注意这里的端口地址，并使用host模式，以方便连接主机的 MySQL 数据库&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;env文件&#34;&gt;&lt;code&gt;.env&lt;/code&gt;文件&lt;/h3&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-ini&#34; data-language=&#34;ini&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-ini&#34;&gt;MAIL_SUBJECT&amp;#x3D;&amp;#39;&amp;#123;&amp;#123;parent.nick | safe&amp;#125;&amp;#125;，『&amp;#123;&amp;#123;site.name | safe&amp;#125;&amp;#125;』上的评论收到了回复&amp;#39;
MAIL_TEMPLATE&amp;#x3D;&amp;#39;&amp;lt;div style&amp;#x3D;&amp;quot;border-radius: 10px 10px 10px 10px;font-size:14px;color:#555555;width: 666px;font-family:&amp;quot;Century Gothic&amp;quot;,&amp;quot;Trebuchet MS&amp;quot;,&amp;quot;Hiragino Sans GB&amp;quot;,微软雅黑,&amp;quot;Microsoft Yahei&amp;quot;,Tahoma,Helvetica,Arial,&amp;quot;SimSun&amp;quot;,sans-serif;margin:50px auto;border:1px solid #eee;max-width:100%;background: #ffffff repeating-linear-gradient(-45deg,#fff,#fff 1.125rem,transparent 1.125rem,transparent 2.25rem);box-shadow: 0 1px 5px rgba(0, 0, 0, 0.15);&amp;quot;&amp;gt;&amp;lt;div style&amp;#x3D;&amp;quot;width:100%;background:#49BDAD;color:#ffffff;border-radius: 10px 10px 0 0;background-image: -moz-linear-gradient(0deg, rgb(67, 198, 184), rgb(255, 209, 244));background-image: -webkit-linear-gradient(0deg, rgb(67, 198, 184), rgb(255, 209, 244));height: 66px;&amp;quot;&amp;gt;&amp;lt;p style&amp;#x3D;&amp;quot;font-size:15px;word-break:break-all;padding: 23px 32px;margin:0;background-color: hsla(0,0%,100%,.4);border-radius: 10px 10px 0 0;&amp;quot;&amp;gt;您在&amp;lt;a style&amp;#x3D;&amp;quot;text-decoration:none;color: #ffffff;&amp;quot; href&amp;#x3D;&amp;quot;&amp;#123;&amp;#123;site.url&amp;#125;&amp;#125;&amp;quot; target&amp;#x3D;&amp;quot;_blank&amp;quot;&amp;gt;&amp;#123;&amp;#123;site.name&amp;#125;&amp;#125;&amp;lt;&amp;#x2F;a&amp;gt;上的留言有新回复啦！&amp;lt;&amp;#x2F;p&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;&amp;lt;div style&amp;#x3D;&amp;quot;margin:40px auto;width:90%&amp;quot;&amp;gt;&amp;lt;p&amp;gt;Hi, &amp;#123;&amp;#123;parent.nick&amp;#125;&amp;#125;，您曾在文章上发表评论：&amp;lt;&amp;#x2F;p&amp;gt;&amp;lt;div style&amp;#x3D;&amp;quot;background: #fafafa repeating-linear-gradient(-45deg,#fff,#fff 1.125rem,transparent 1.125rem,transparent 2.25rem);box-shadow: 0 2px 5px rgba(0, 0, 0, 0.15);margin:20px 0px;padding:15px;border-radius:5px;font-size:14px;color:#555555;&amp;quot;&amp;gt;&amp;#123;&amp;#123;self.comment | safe&amp;#125;&amp;#125;&amp;lt;&amp;#x2F;div&amp;gt;&amp;lt;p&amp;gt;&amp;lt;strong&amp;gt;&amp;#123;&amp;#123;self.nick&amp;#125;&amp;#125;&amp;lt;&amp;#x2F;strong&amp;gt; 给您的回复如下：&amp;lt;&amp;#x2F;p&amp;gt;&amp;lt;div style&amp;#x3D;&amp;quot;background:#fafafa repeating-linear-gradient(-45deg,#fff,#fff 1.125rem,transparent 1.125rem,transparent 2.25rem);box-shadow: 0 2px 5px rgba(0, 0, 0, 0.15);margin:20px 0px;padding:15px;border-radius:5px;font-size:14px;color:#555555;&amp;quot;&amp;gt;&amp;#123;&amp;#123;self.comment | safe&amp;#125;&amp;#125;&amp;lt;&amp;#x2F;div&amp;gt;&amp;lt;p&amp;gt;您可以点击&amp;lt;a style&amp;#x3D;&amp;quot;text-decoration:none; color:#12addb&amp;quot; href&amp;#x3D;&amp;quot;&amp;#123;&amp;#123;site.postUrl&amp;#125;&amp;#125;&amp;quot; target&amp;#x3D;&amp;quot;_blank&amp;quot;&amp;gt;查看回复的完整內容&amp;lt;&amp;#x2F;a&amp;gt;，欢迎再次光临&amp;lt;a style&amp;#x3D;&amp;quot;text-decoration:none; color:#12addb&amp;quot; href&amp;#x3D;&amp;quot;&amp;#123;&amp;#123;site.url&amp;#125;&amp;#125;&amp;quot; target&amp;#x3D;&amp;quot;_blank&amp;quot;&amp;gt;&amp;#123;&amp;#123;site.name&amp;#125;&amp;#125;&amp;lt;&amp;#x2F;a&amp;gt;。&amp;lt;hr &amp;#x2F;&amp;gt;&amp;lt;p style&amp;#x3D;&amp;quot;font-size:12px;color:#b7adad&amp;quot;&amp;gt;本邮件为系统自动发送，请勿直接回复邮件哦，可到博文内容回复。&amp;lt;&amp;#x2F;p&amp;gt;&amp;lt;&amp;#x2F;p&amp;gt;&amp;lt;style type&amp;#x3D;&amp;quot;text&amp;#x2F;css&amp;quot;&amp;gt;a:link&amp;#123;text-decoration:none&amp;#125;a:visited&amp;#123;text-decoration:none&amp;#125;a:hover&amp;#123;text-decoration:none&amp;#125;a:active&amp;#123;text-decoration:none&amp;#125;&amp;lt;&amp;#x2F;style&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;&amp;#39;
MAIL_SUBJECT_ADMIN&amp;#x3D;&amp;#39;&amp;#123;&amp;#123;site.name | safe&amp;#125;&amp;#125; 上有新评论了&amp;#39;
MAIL_TEMPLATE_ADMIN&amp;#x3D;&amp;#39;&amp;lt;div style&amp;#x3D;&amp;quot;border-radius: 10px 10px 10px 10px;font-size:14px;color:#555555;width: 666px;font-family:&amp;quot;Century Gothic&amp;quot;,&amp;quot;Trebuchet MS&amp;quot;,&amp;quot;Hiragino Sans GB&amp;quot;,微软雅黑,&amp;quot;Microsoft Yahei&amp;quot;,Tahoma,Helvetica,Arial,&amp;quot;SimSun&amp;quot;,sans-serif;margin:50px auto;border:1px solid #eee;max-width:100%;background: #ffffff repeating-linear-gradient(-45deg,#fff,#fff 1.125rem,transparent 1.125rem,transparent 2.25rem);box-shadow: 0 1px 5px rgba(0, 0, 0, 0.15);&amp;quot;&amp;gt;&amp;lt;div style&amp;#x3D;&amp;quot;width:100%;background:#49BDAD;color:#ffffff;border-radius: 10px 10px 0 0;background-image: -moz-linear-gradient(0deg, rgb(67, 198, 184), rgb(255, 209, 244));background-image: -webkit-linear-gradient(0deg, rgb(67, 198, 184), rgb(255, 209, 244));height: 66px;&amp;quot;&amp;gt;&amp;lt;p style&amp;#x3D;&amp;quot;font-size:15px;word-break:break-all;padding: 23px 32px;margin:0;background-color: hsla(0,0%,100%,.4);border-radius: 10px 10px 0 0;&amp;quot;&amp;gt;您在&amp;lt;a style&amp;#x3D;&amp;quot;text-decoration:none;color: #ffffff;&amp;quot;href&amp;#x3D;&amp;quot;&amp;#123;&amp;#123;site.url&amp;#125;&amp;#125;&amp;quot;target&amp;#x3D;&amp;quot;_blank&amp;quot;&amp;gt;&amp;#123;&amp;#123;site.name&amp;#125;&amp;#125;&amp;lt;&amp;#x2F;a&amp;gt;上的留言有新评论啦！&amp;lt;&amp;#x2F;p&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;&amp;lt;div style&amp;#x3D;&amp;quot;margin:40px auto;width:90%&amp;quot;&amp;gt;&amp;lt;p&amp;gt;&amp;#123;&amp;#123;self.nick&amp;#125;&amp;#125;回复说：&amp;lt;&amp;#x2F;p&amp;gt;&amp;lt;div style&amp;#x3D;&amp;quot;background: #fafafa repeating-linear-gradient(-45deg,#fff,#fff 1.125rem,transparent 1.125rem,transparent 2.25rem);box-shadow: 0 2px 5px rgba(0, 0, 0, 0.15);margin:20px 0px;padding:15px;border-radius:5px;font-size:14px;color:#555555;&amp;quot;&amp;gt;&amp;#123;&amp;#123;self.comment | safe&amp;#125;&amp;#125;&amp;lt;&amp;#x2F;div&amp;gt;&amp;lt;p&amp;gt;您可以点击&amp;lt;a style&amp;#x3D;&amp;quot;text-decoration:none; color:#12addb&amp;quot;href&amp;#x3D;&amp;quot;&amp;#123;&amp;#123;site.postUrl&amp;#125;&amp;#125;&amp;quot;target&amp;#x3D;&amp;quot;_blank&amp;quot;&amp;gt;查看回复的完整內容&amp;lt;&amp;#x2F;a&amp;gt;。&amp;lt;hr&amp;#x2F;&amp;gt;&amp;lt;&amp;#x2F;p&amp;gt;&amp;lt;style type&amp;#x3D;&amp;quot;text&amp;#x2F;css&amp;quot;&amp;gt;a:link&amp;#123;text-decoration:none&amp;#125;a:visited&amp;#123;text-decoration:none&amp;#125;a:hover&amp;#123;text-decoration:none&amp;#125;a:active&amp;#123;text-decoration:none&amp;#125;&amp;lt;&amp;#x2F;style&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;&amp;#39;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;blockquote&gt;
&lt;p&gt;由于单引号和双引号过多，邮件通知模板只能放在env文件里面&lt;/p&gt;
&lt;p&gt;这个邮件通知模板效果如下&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/02/21/20230221011317-4.webp&#34; alt=&#34;Waline 邮件通知&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;安装waline&#34;&gt;安装waline&lt;/h3&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-bash&#34; data-language=&#34;bash&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-bash&#34;&gt;docker-compose -p &amp;quot;container&amp;quot; -f .&amp;#x2F;vps.yml up -d --build&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;h2 id=&#34;域名配置&#34;&gt;域名配置&lt;/h2&gt;
&lt;h3 id=&#34;域名设置&#34;&gt;域名设置&lt;/h3&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/02/21/20230221011317-5.webp&#34; alt=&#34;waline 域名配置&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;设置反向代理&#34;&gt;设置反向代理&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;宝塔设置反向代理方法如下&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/02/21/20230221011317-6.webp&#34; alt=&#34;waline 反向代理配置&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;DNS-配置&#34;&gt;DNS 配置&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;这里以DNSPod 为例&lt;/p&gt;
&lt;p&gt;直接使用ip就是如下示例&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/02/21/20230221011317-7.webp&#34; alt=&#34;DNSpod 配置&#34;&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;如果使用vercel ，那么域名配置方法如下&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;code&gt;cname-china.vercel-dns.com&lt;/code&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/02/21/20230221011317-8.webp&#34; alt=&#34;vercel 部署 waline dns 配置&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;添加-GitHub-社交登录&#34;&gt;添加 GitHub 社交登录&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;开启 GitHub 账号登录功能需要配置 GitHub OAuth 密钥。点击 &lt;a href=&#34;https://github.com/settings/applications/new&#34;&gt;Register a new OAuth application&lt;/a&gt; 进入 GitHub OAuth 应用申请页面。&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;配置注意事项如下:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Application name: 应用名称，会在用户授权时显示，推荐使用博客名称。&lt;/li&gt;
&lt;li&gt;Homepage URL: 应用主页地址，会在用户授权时显示，推荐使用博客地址。&lt;/li&gt;
&lt;li&gt;Appcation description: 应用描述，会在用户授权时显示，非必填项。&lt;/li&gt;
&lt;li&gt;Authorization callback URL: 应用的回调地址，登录时需要使用。填入 &lt;code&gt;&amp;lt;serverURL&amp;gt;/oauth/github&lt;/code&gt; 其中 &lt;code&gt;&amp;lt;serverURL&amp;gt;&lt;/code&gt; 是你的 Waline 服务端地址。&lt;/li&gt;
&lt;/ul&gt;
&lt;ol start=&#34;2&#34;&gt;
&lt;li&gt;填写完成后点击 Register application 即可成功创建。页面中会显示 Client ID。点击 Client secrets 栏右边的 Generate a new client secret 按钮则可以获取到该应用的 Client secrets。&lt;/li&gt;
&lt;/ol&gt;
&lt;blockquote&gt;
&lt;p&gt;显示在 GitHub的 &lt;code&gt;Settings -&amp;gt; Developer settings -&amp;gt; OAuth Apps -&amp;gt; 又见苍岚&lt;/code&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/02/21/20230221011317-9.webp&#34; alt=&#34;github 社交登录配置&#34;&gt;&lt;/p&gt;
&lt;ol start=&#34;3&#34;&gt;
&lt;li&gt;使用以上信息配置环境变量，重新部署。&lt;/li&gt;
&lt;/ol&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;环境变量名称&lt;/th&gt;
&lt;th&gt;备注&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;GITHUB_ID&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;对应 GitHub OAuth App 中的 Client ID&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;code&gt;GITHUB_SECRET&lt;/code&gt;&lt;/td&gt;
&lt;td&gt;对应 GitHub OAuth App 中的 Client secrets&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;之后即可使用 GitHub 登录&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/02/21/20230221011317-10.webp&#34; alt=&#34;github waline 登录&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;添加邮件通知&#34;&gt;添加邮件通知&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;上文中已经在 docker compose 文件中添加了邮件通知功能，下面介绍另一个邮件通知模板&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;紫罗兰永恒花园信笺模板&#34;&gt;紫罗兰永恒花园信笺模板&lt;/h3&gt;
