&lt;h4 id=&#34;Line-Easing-Visualizing&#34;&gt;&lt;a href=&#34;https://echarts.apache.org/examples/zh/editor.html?c=line-easing&#34;&gt;Line Easing Visualizing&lt;/a&gt;&lt;/h4&gt;
&lt;script&gt;
var easingFuncs = {
    linear: function (k) {
        return k;
    },
    quadraticIn: function (k) {
        return k * k;
    },
    quadraticOut: function (k) {
        return k * (2 - k);
    },
    quadraticInOut: function (k) {
        if ((k *= 2) &lt; 1) { return 0.5 * k * k; }
        return -0.5 * (--k * (k - 2) - 1);
    },
    cubicIn: function (k) {
        return k * k * k;
    },
    cubicOut: function (k) {
        return --k * k * k + 1;
    },
    cubicInOut: function (k) {
        if ((k *= 2) &lt; 1) { return 0.5 * k * k * k; }
        return 0.5 * ((k -= 2) * k * k + 2);
    },
    quarticIn: function (k) {
        return k * k * k * k;
    },
    quarticOut: function (k) {
        return 1 - (--k * k * k * k);
    },
    quarticInOut: function (k) {
        if ((k *= 2) &lt; 1) { return 0.5 * k * k * k * k; }
        return -0.5 * ((k -= 2) * k * k * k - 2);
    },
    quinticIn: function (k) {
        return k * k * k * k * k;
    },
    quinticOut: function (k) {
        return --k * k * k * k * k + 1;
    },
    quinticInOut: function (k) {
        if ((k *= 2) &lt; 1) { return 0.5 * k * k * k * k * k; }
        return 0.5 * ((k -= 2) * k * k * k * k + 2);
    },
    sinusoidalIn: function (k) {
        return 1 - Math.cos(k * Math.PI / 2);
    },
    sinusoidalOut: function (k) {
        return Math.sin(k * Math.PI / 2);
    },
    sinusoidalInOut: function (k) {
        return 0.5 * (1 - Math.cos(Math.PI * k));
    },
    exponentialIn: function (k) {
        return k === 0 ? 0 : Math.pow(1024, k - 1);
    },
    exponentialOut: function (k) {
        return k === 1 ? 1 : 1 - Math.pow(2, -10 * k);
    },
    exponentialInOut: function (k) {
        if (k === 0) {
            return 0;
        }
        if (k === 1) {
            return 1;
        }
        if ((k *= 2) &lt; 1) {
            return 0.5 * Math.pow(1024, k - 1);
        }
        return 0.5 * (-Math.pow(2, -10 * (k - 1)) + 2);
    },
    circularIn: function (k) {
        return 1 - Math.sqrt(1 - k * k);
    },
    circularOut: function (k) {
        return Math.sqrt(1 - (--k * k));
    },
    circularInOut: function (k) {
        if ((k *= 2) &lt; 1) { return -0.5 * (Math.sqrt(1 - k * k) - 1); }
        return 0.5 * (Math.sqrt(1 - (k -= 2) * k) + 1);
    },
    elasticIn: function (k) {
        var s;
        var a = 0.1;
        var p = 0.4;
        if (k === 0) { return 0; }
        if (k === 1) { return 1; }
        if (!a || a &lt; 1) { a = 1; s = p / 4; }
        else { s = p * Math.asin(1 / a) / (2 * Math.PI); }
        return -(a * Math.pow(2, 10 * (k -= 1)) * Math.sin((k - s) * (2 * Math.PI) / p));
    },
    elasticOut: function (k) {
        var s;
        var a = 0.1;
        var p = 0.4;
        if (k === 0) { return 0; }
        if (k === 1) { return 1; }
        if (!a || a &lt; 1) { a = 1; s = p / 4; }
        else { s = p * Math.asin(1 / a) / (2 * Math.PI); }
        return (a * Math.pow(2, -10 * k) * Math.sin((k - s) * (2 * Math.PI) / p) + 1);
    },
    elasticInOut: function (k) {
        var s;
        var a = 0.1;
        var p = 0.4;
        if (k === 0) { return 0; }
        if (k === 1) { return 1; }
        if (!a || a &lt; 1) { a = 1; s = p / 4; }
        else { s = p * Math.asin(1 / a) / (2 * Math.PI); }
        if ((k *= 2) &lt; 1) {
            return -0.5 * (a * Math.pow(2, 10 * (k -= 1)) * Math.sin((k - s) * (2 * Math.PI) / p));
        }
        return a * Math.pow(2, -10 * (k -= 1)) * Math.sin((k - s) * (2 * Math.PI) / p) * 0.5 + 1;
    },
    backIn: function (k) {
        var s = 1.70158;
        return k * k * ((s + 1) * k - s);
    },
    backOut: function (k) {
        var s = 1.70158;
        return --k * k * ((s + 1) * k + s) + 1;
    },
    backInOut: function (k) {
        var s = 1.70158 * 1.525;
        if ((k *= 2) &lt; 1) { return 0.5 * (k * k * ((s + 1) * k - s)); }
        return 0.5 * ((k -= 2) * k * ((s + 1) * k + s) + 2);
    },
    bounceIn: function (k) {
        return 1 - easingFuncs.bounceOut(1 - k);
    },
    bounceOut: function (k) {
        if (k &lt; (1 / 2.75)) { return 7.5625 * k * k; }
        else if (k &lt; (2 / 2.75)) { return 7.5625 * (k -= (1.5 / 2.75)) * k + 0.75; }
        else if (k &lt; (2.5 / 2.75)) { return 7.5625 * (k -= (2.25 / 2.75)) * k + 0.9375; }
        else { return 7.5625 * (k -= (2.625 / 2.75)) * k + 0.984375; }
    },
    bounceInOut: function (k) {
        if (k &lt; 0.5) { return easingFuncs.bounceIn(k * 2) * 0.5; }
        return easingFuncs.bounceOut(k * 2 - 1) * 0.5 + 0.5;
    }
};

var N_POINT = 30;

var grids = [];
var xAxes = [];
var yAxes = [];
var series = [];
var titles = [];
var count = 0;
echarts.util.each(easingFuncs, function (easingFunc, name) {
    var data = [];
    for (var i = 0; i &lt;= N_POINT; i++) {
        var x = i / N_POINT;
        var y = easingFunc(x);
        data.push([x, y]);
    }
    grids.push({
        show: true,
        borderWidth: 0,
        backgroundColor: &#39;#fff&#39;,
        shadowColor: &#39;rgba(0, 0, 0, 0.3)&#39;,
        shadowBlur: 2
    });
    xAxes.push({
        type: &#39;value&#39;,
        show: false,
        min: 0,
        max: 1,
        gridIndex: count
    });
    yAxes.push({
        type: &#39;value&#39;,
        show: false,
        min: -0.4,
        max: 1.4,
        gridIndex: count
    });
    series.push({
        name: name,
        type: &#39;line&#39;,
        xAxisIndex: count,
        yAxisIndex: count,
        data: data,
        showSymbol: false,
        animationEasing: name,
        animationDuration: 1000
    });
    titles.push({
        textAlign: &#39;center&#39;,
        text: name,
        textStyle: {
            fontSize: 12,
            fontWeight: &#39;normal&#39;
        }
    });
    count++;
});

var rowNumber = Math.ceil(Math.sqrt(count));
echarts.util.each(grids, function (grid, idx) {
    grid.left = ((idx % rowNumber) / rowNumber * 100 + 0.5) + &#39;%&#39;;
    grid.top = (Math.floor(idx / rowNumber) / rowNumber * 100 + 0.5) + &#39;%&#39;;
    grid.width = (1 / rowNumber * 100 - 1) + &#39;%&#39;;
    grid.height = (1 / rowNumber * 100 - 1) + &#39;%&#39;;

    titles[idx].left = parseFloat(grid.left) + parseFloat(grid.width) / 2 + &#39;%&#39;;
    titles[idx].top = parseFloat(grid.top) + &#39;%&#39;;
});
&lt;/script&gt;
&lt;div id=&#34;echarts7286&#34; style=&#34;width: 85%;height: 400px;margin: 0 auto&#34;&gt;&lt;/div&gt;
&lt;script type=&#34;text/javascript&#34;&gt;
        // 基于准备好的dom，初始化echarts实例
        var myChart = echarts.init(document.getElementById(&#39;echarts7286&#39;));

        // 指定图表的配置项和数据
        var option = option = {
    title: titles.concat([{
        text: &#39;Different Easing Functions&#39;,
        top: &#39;bottom&#39;,
        left: &#39;center&#39;
    }]),
    grid: grids,
    xAxis: xAxes,
    yAxis: yAxes,
    series: series
};

        // 使用刚指定的配置项和数据显示图表。
        myChart.setOption(option);
&lt;/script&gt;
&lt;h3 id=&#34;柱状图Bar&#34;&gt;柱状图Bar&lt;/h3&gt;
&lt;h4 id=&#34;柱状图动画延迟&#34;&gt;&lt;a href=&#34;https://echarts.apache.org/examples/zh/editor.html?c=bar-animation-delay&#34;&gt;柱状图动画延迟&lt;/a&gt;&lt;/h4&gt;
&lt;script&gt;
var xAxisData = [];
var data01 = [];
var data02 = [];
for (var i = 0; i &lt; 100; i++) {
    xAxisData.push(&#39;类目&#39; + i);
    data01.push((Math.sin(i / 5) * (i / 5 -10) + i / 6) * 5);
    data02.push((Math.cos(i / 5) * (i / 5 -10) + i / 6) * 5);
}
&lt;/script&gt;
&lt;div id=&#34;echarts7840&#34; style=&#34;width: 85%;height: 400px;margin: 0 auto&#34;&gt;&lt;/div&gt;
&lt;script type=&#34;text/javascript&#34;&gt;
        // 基于准备好的dom，初始化echarts实例
        var myChart = echarts.init(document.getElementById(&#39;echarts7840&#39;));

        // 指定图表的配置项和数据
        var option = option = {
    title: {
        text: &#39;柱状图动画延迟&#39;
    },
    legend: {
        data: [&#39;bar01&#39;, &#39;bar02&#39;]
    },
    toolbox: {
        // y: &#39;bottom&#39;,
        feature: {
            magicType: {
                type: [&#39;stack&#39;, &#39;tiled&#39;]
            },
            dataView: {},
            saveAsImage: {
                pixelRatio: 2
            }
        }
    },
    tooltip: {},
    xAxis: {
        data: xAxisData,
        splitLine: {
            show: false
        }
    },
    yAxis: {
    },
    series: [{
        name: &#39;bar01&#39;,
        type: &#39;bar&#39;,
        data: data01,
        animationDelay: function (idx) {
            return idx * 10 + 50;
        }
    }, {
        name: &#39;bar02&#39;,
        type: &#39;bar&#39;,
        data: data02,
        animationDelay: function (idx) {
            return idx * 10 + 100;
        }
    }],
    animationEasing: &#39;elasticOut&#39;,
    animationDelayUpdate: function (idx) {
        return idx * 5;
    }
};

        // 使用刚指定的配置项和数据显示图表。
        myChart.setOption(option);
