&lt;div id=&#34;echarts9694&#34; style=&#34;width: 85%;height: 400px;margin: 0 auto&#34;&gt;&lt;/div&gt;
&lt;script type=&#34;text/javascript&#34;&gt;
        // 基于准备好的dom，初始化echarts实例
        var myChart = echarts.init(document.getElementById(&#39;echarts9694&#39;));

        // 指定图表的配置项和数据
        var option = option = {
    tooltip: {},
    backgroundColor: &#39;#fff&#39;,
    visualMap: {
        show: false,
        dimension: 2,
        min: -1,
        max: 1,
        inRange: {
            color: [&#39;#313695&#39;, &#39;#4575b4&#39;, &#39;#74add1&#39;, &#39;#abd9e9&#39;, &#39;#e0f3f8&#39;, &#39;#ffffbf&#39;, &#39;#fee090&#39;, &#39;#fdae61&#39;, &#39;#f46d43&#39;, &#39;#d73027&#39;, &#39;#a50026&#39;]
        }
    },
    xAxis3D: {
        type: &#39;value&#39;
    },
    yAxis3D: {
        type: &#39;value&#39;
    },
    zAxis3D: {
        type: &#39;value&#39;,
        max: 1,
        splitNumber: 2
    },
    grid3D: {
        viewControl: {
            // projection: &#39;orthographic&#39;
        },
        boxHeight: 40
    },
    series: [{
        type: &#39;surface&#39;,
        wireframe: {
            show: false
        },
        shading: &#39;color&#39;,
        equation: {
            x: {
                step: 0.05,
                min: -3,
                max: 3,
            },
            y: {
                step: 0.05,
                min: -3,
                max: 3,
            },
            z: function (x, y) {
                return Math.sin(x * x + y * y) * x / 3.14
            }
        }
    }]
}

