&lt;h2 id=&#34;添加博客看板娘&#34;&gt;添加博客看板娘&lt;/h2&gt;
&lt;p&gt;方法如下：&lt;/p&gt;
&lt;p&gt;安装插件：&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-bash&#34; data-language=&#34;bash&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-bash&#34;&gt;npm install --save hexo-helper-live2d&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;p&gt;安装喜欢的模型：&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-bash&#34; data-language=&#34;bash&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-bash&#34;&gt;$ npm install packagename
#安装下载动画人物库, 动画人物有很多, 可以网上查询资料, 下面推荐几种.
npm install --save live2d-widget-model-shizuku #课桌女孩
npm install --save live2d-widget-model-hibiki  #御姐
npm install --save live2d-widget-model-wanko   #狗狗
npm install --save live2d-widget-model-haruto  #海军服女孩
npm install --save live2d-widget-model-miku    #萝莉&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;p&gt;将packagename换成模型名字，如我使用的模型：&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-bash&#34; data-language=&#34;bash&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-bash&#34;&gt;$ npm install live2d-widget-model-shizuku&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;p&gt;然后打开博客根目录下的 _config.yml文件，添加如下代码：&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;使用本地模型方式：&lt;/strong&gt;&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-yaml&#34; data-language=&#34;yaml&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-yaml&#34;&gt;## 添加动画live2d模块  npm install --save hexo-helper-live2d
## 下载动画人物库 npm install live2d-widget-model-z16 -D
live2d:
  enable: true
  scriptFrom: local # 默认
  pluginRootPath: live2dw&amp;#x2F; # 插件在站点上的根目录(相对路径)
  pluginJsPath: lib&amp;#x2F; # 脚本文件相对与插件根目录路径
  pluginModelPath: assets&amp;#x2F; # 模型文件相对与插件根目录路径
  tagMode: false # 标签模式, 是否仅替换 live2d tag标签而非插入到所有页面中
  debug: false # 调试, 是否在控制台输出日志
  model:
    use: live2d-widget-model-miku
  display:
    position: right #动画位置
    width: 150
    height: 190
    # 位置配置，这个在左侧边栏位置很居中
    hOffset: 50  # 调节水平位置
    vOffset: -5  # 调节垂直位置
  mobile:
    show: false # 是否在移动设备上显示
    scale: 0.5 # 移动设备上的缩放
  react:
    opacityDefault: 0.7
    opacityOnHover: 0.8&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;p&gt;&lt;strong&gt;使用网络模型方式：&lt;/strong&gt;&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-yaml&#34; data-language=&#34;yaml&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-yaml&#34;&gt;# Live2D
## https:&amp;#x2F;&amp;#x2F;github.com&amp;#x2F;EYHN&amp;#x2F;hexo-helper-live2d
live2d:
  enable: true
  # enable: false
  pluginRootPath: live2dw&amp;#x2F; # Root path of plugin to be on the site (Relative)
  pluginJsPath: lib&amp;#x2F; # JavaScript path related to plugin&amp;#39;s root (Relative)
  pluginModelPath: assets&amp;#x2F; # Relative model path related to plugin&amp;#39;s root (Relative)
  scriptFrom: local # Default
  # scriptFrom: jsdelivr # jsdelivr CDN
  # scriptFrom: unpkg # unpkg CDN
  # scriptFrom: https:&amp;#x2F;&amp;#x2F;cdn.jsdelivr.net&amp;#x2F;npm&amp;#x2F;live2d-widget@3.x&amp;#x2F;lib&amp;#x2F;L2Dwidget.min.js # Your custom url
  tagMode: false # Whether only to replace live2d tag instead of inject to all pages
  log: false # Whether to show logs in console
  model:
    #use: live2d-widget-model-lwet # npm-module package name
    # use: wanko # folder name in (hexo base dir)&amp;#x2F;live2d_models&amp;#x2F;
    # use: .&amp;#x2F;wives&amp;#x2F;wanko # folder path relative to hexo base dir
    # 模型：https:&amp;#x2F;&amp;#x2F;huaji8.top&amp;#x2F;post&amp;#x2F;live2d-plugin-2.0&amp;#x2F;
    use: https:&amp;#x2F;&amp;#x2F;cdn.jsdelivr.net&amp;#x2F;npm&amp;#x2F;live2d-widget-model-wanko@1.0.5&amp;#x2F;assets&amp;#x2F;wanko.model.json # Your custom url
  display:
    position: left
    width: 300
    height: 400
    hOffset: 50
    vOffset: 10
  mobile:
    show: false&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;p&gt;见右下角&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/03/14/20230314054810.webp&#34; alt=&#34;Live2D看板娘&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;更强大的看板娘&#34;&gt;更强大的看板娘&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;&lt;strong&gt;&lt;a href=&#34;https://github.com/stevenjoezhang/live2d-widget&#34;&gt;live2d-widget&lt;/a&gt;&lt;/strong&gt; &lt;a href=&#34;https://www.fghrsh.net/post/123.html&#34;&gt;原作者教程&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;支持换装，模型切换，对话框，拍照，小游戏，眼神跟随，触摸对话，音频等。&lt;/p&gt;
&lt;p&gt;可以自建api，自定义各种模型，各种对话等。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/03/14/20230314145639.webp&#34; alt=&#34;live2d看板娘&#34;&gt;&lt;/p&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/03/14/20230314145639-1.webp&#34; alt=&#34;live2d-widget效果图&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;依赖-Font-Awesome&#34;&gt;依赖  Font Awesome&lt;/h3&gt;
&lt;p&gt;请在 &lt;code&gt;&amp;lt;head&amp;gt;&lt;/code&gt; 中加入。在Matery中自带，这一步跳过。&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-javascript&#34; data-language=&#34;javascript&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-javascript&#34;&gt;&amp;lt;link rel&amp;#x3D;&amp;quot;stylesheet&amp;quot; href&amp;#x3D;&amp;quot;https:&amp;#x2F;&amp;#x2F;cdn.jsdelivr.net&amp;#x2F;npm&amp;#x2F;font-awesome&amp;#x2F;css&amp;#x2F;font-awesome.min.css&amp;quot;&amp;gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;h3 id=&#34;使用-Usage&#34;&gt;使用 Usage&lt;/h3&gt;
&lt;p&gt;将这一行代码加入 &lt;code&gt;&amp;lt;head&amp;gt;&lt;/code&gt; 或 &lt;code&gt;&amp;lt;body&amp;gt;&lt;/code&gt;，即可展现出效果：&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-javascript&#34; data-language=&#34;javascript&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-javascript&#34;&gt;&amp;lt;script src&amp;#x3D;&amp;quot;https:&amp;#x2F;&amp;#x2F;cdn.jsdelivr.net&amp;#x2F;gh&amp;#x2F;17lai&amp;#x2F;live2d-widget@latest&amp;#x2F;autoload.js&amp;quot;&amp;gt;&amp;lt;&amp;#x2F;script&amp;gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;h3 id=&#34;后端-API&#34;&gt;后端 API&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;initWidget&lt;/code&gt; 方法接受名为 &lt;code&gt;apiPath&lt;/code&gt; 和 &lt;code&gt;cdnPath&lt;/code&gt; 的参数，两者设置其中一项即可。其中 &lt;code&gt;apiPath&lt;/code&gt; 为后端 API 的 URL，可以自行搭建，并增加模型（需要修改的内容比较多，此处不再赘述）。而 &lt;code&gt;cdnPath&lt;/code&gt; 则是通过 jsDelivr 这样的 CDN 服务加载资源，更加稳定。&lt;/p&gt;
&lt;h3 id=&#34;目录结构-Files&#34;&gt;目录结构 Files&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;waifu-tips.js&lt;/code&gt; 包含了按钮和对话框的逻辑；&lt;/li&gt;
&lt;li&gt;&lt;code&gt;waifu-tips.json&lt;/code&gt; 中定义了触发条件（&lt;code&gt;selector&lt;/code&gt;，CSS 选择器）和触发时显示的文字（&lt;code&gt;text&lt;/code&gt;）；&lt;/li&gt;
&lt;li&gt;&lt;code&gt;waifu.css&lt;/code&gt; 是看板娘的样式表。&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;使用 &lt;code&gt;waifu-tips.json&lt;/code&gt; 自定义 &lt;code&gt;selector&lt;/code&gt;触发提示文字框，可以用来做菜单，按钮的导航提示，终于是个合格的看板娘了！&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;对所有菜单，常用按钮做了基本文字提示。鼠标去到处戳一下，看看触发提示！😄&lt;/li&gt;
&lt;li&gt;这是一个不小的工程，难度不高，趣味性很强。&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img src=&#34;https://cimg1.17lai.site/data/2023/03/14/20230314054810-2.webp&#34; alt=&#34;看板娘触发文字提示&#34;&gt;&lt;/p&gt;
&lt;h2 id=&#34;添加夜间模式切换&#34;&gt;添加夜间模式切换&lt;/h2&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;下面这个还远未完善，只是基本可用，不少细节地方CSS需要完善&lt;/li&gt;
&lt;li&gt;已经由博主上传到官方 develop 分支了&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;设置基础样式&#34;&gt;设置基础样式&lt;/h3&gt;
&lt;p&gt;参考其他优秀产品的黑夜模式，得出共性：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;那就是黑夜模式的背景一般不会是纯黑（#000）；而是淡黑色，字体也不是纯白（#fff）而浅白色&lt;/li&gt;
&lt;li&gt;图片亮度降低&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;下面就开始贴代码了&lt;/p&gt;
&lt;p&gt;在 &lt;code&gt;themes&amp;gt;hexo-theme-matery&amp;gt;source&amp;gt;css&amp;gt;matery.css&lt;/code&gt; 中加上下面的代码&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-css&#34; data-language=&#34;css&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-css&#34;&gt;&amp;#x2F;* 字体颜色变灰白色 *&amp;#x2F;
body.DarkMode .fas,
body.DarkMode .title,
body.DarkMode .row .text,
body.DarkMode article .article-content .summary,
body.DarkMode .card .card-image .card-title,
body.DarkMode .fa-moon-o:before,
body.DarkMode .fa-lightbulb-o:before,
body.DarkMode article .article-tags .chip,
body.DarkMode .chip-container .tag-title,
body.DarkMode div.jqcloud a,
body.DarkMode .friends-container .tag-title,
body.DarkMode .frind-ship .title h1,
body.DarkMode .card .card-content p,
body.DarkMode .card .card-content .dss,
body.DarkMode .v[data-class&amp;#x3D;&amp;#39;v&amp;#39;] .vcount,
body.DarkMode .v[data-class&amp;#x3D;&amp;#39;v&amp;#39;] .vcount .vnum,
body.DarkMode pre code,
body.DarkMode h1,
body.DarkMode h2,
body.DarkMode h3,
body.DarkMode h4,
body.DarkMode h5,
body.DarkMode h6,
body.DarkMode li,
body.DarkMode p,
body.DarkMode header .side-nav .mobile-head .logo-name,
body.DarkMode header .side-nav .mobile-head .logo-desc,
body.DarkMode header .side-nav .menu-list a,
body.DarkMode .bg-cover .post-title,
body.DarkMode.read .bg-cover .description &amp;#123;
    color: rgba(255, 255, 255, 0.6);
&amp;#125;

&amp;#x2F;* 背景颜色变灰色 *&amp;#x2F;
body.DarkMode .card,
body.DarkMode .block-with-text:after &amp;#123;
    background-color: #282c34;
&amp;#125;

&amp;#x2F;* 背景颜色变黑色 *&amp;#x2F;
body.DarkMode,
body.DarkMode .v[data-class&amp;#x3D;&amp;#39;v&amp;#39;] .vcount,
body.DarkMode #rewardModal .modal-content,
body.DarkMode .modal,
body.DarkMode header .side-nav,
body.DarkMode header .side-nav .menu-list .m-nav-show &amp;#123;
    background-color: #12121c;
&amp;#125;

&amp;#x2F;* 改变透明度 *&amp;#x2F;
body.DarkMode .aplayer &amp;#123;
    background: #2f3742 !important;
&amp;#125;

body.DarkMode img,
body.DarkMode strong &amp;#123;
    filter: brightness(0.7);
&amp;#125;

&amp;#x2F;*toc目录滤镜*&amp;#x2F;
body.DarkMode .toc-widget &amp;#123;
    filter: invert(0.8);
&amp;#125;

body.DarkMode .toc-widget .toc-list-item &amp;#123;
    color: #000
&amp;#125;

&amp;#x2F;* Skill bar text color *&amp;#x2F;
body.DarkMode .skillbar .skill-bar-percent &amp;#123;
    color: #000;
&amp;#125;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;h3 id=&#34;切换按钮&#34;&gt;切换按钮&lt;/h3&gt;
&lt;p&gt;完成了背景、字体、图片的样式，就需要黑夜白天切换按钮了&lt;/p&gt;
&lt;p&gt;在 &lt;code&gt;themes&amp;gt;hexo-theme-matery&amp;gt;layout&amp;gt;_widget&lt;/code&gt; 中创建一个新的文件 &lt;strong&gt;day-night.ejs&lt;/strong&gt;，在新建的文件中加入下面的代码&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-ejs&#34; data-language=&#34;ejs&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-ejs&#34;&gt;&amp;lt;!-- 白天和黑夜主题 --&amp;gt;
&amp;lt;div class&amp;#x3D;&amp;quot;sum-moon-box&amp;quot;&amp;gt;
  &amp;lt;a class&amp;#x3D;&amp;quot;btn-floating btn-large waves-effect waves-light&amp;quot; onclick&amp;#x3D;&amp;quot;switchNightMode()&amp;quot; title&amp;#x3D;&amp;quot;切换主题&amp;quot; &amp;gt;
    &amp;lt;i id&amp;#x3D;&amp;quot;sum-moon-icon&amp;quot; class&amp;#x3D;&amp;quot;fas fa-sun&amp;quot; style&amp;#x3D;&amp;quot;width:48px; height:48px; font-size: 28px;&amp;quot;&amp;gt;&amp;lt;&amp;#x2F;i&amp;gt;
  &amp;lt;&amp;#x2F;a&amp;gt;
&amp;lt;&amp;#x2F;div&amp;gt;

&amp;lt;script&amp;gt;
  function switchNightMode() &amp;#123;
    $(&amp;#39;&amp;lt;div class&amp;#x3D;&amp;quot;Cuteen_DarkSky&amp;quot;&amp;gt;&amp;lt;div class&amp;#x3D;&amp;quot;Cuteen_DarkPlanet&amp;quot;&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;&amp;#39;).appendTo($(&amp;#39;body&amp;#39;)),
      setTimeout(function () &amp;#123;
        $(&amp;#39;body&amp;#39;).hasClass(&amp;#39;DarkMode&amp;#39;) 
        ? ($(&amp;#39;body&amp;#39;).removeClass(&amp;#39;DarkMode&amp;#39;), localStorage.setItem(&amp;#39;isDark&amp;#39;, &amp;#39;0&amp;#39;), $(&amp;#39;#sum-moon-icon&amp;#39;).removeClass(&amp;quot;fa-sun&amp;quot;).addClass(&amp;#39;fa-moon&amp;#39;)) 
        : ($(&amp;#39;body&amp;#39;).addClass(&amp;#39;DarkMode&amp;#39;), localStorage.setItem(&amp;#39;isDark&amp;#39;, &amp;#39;1&amp;#39;), $(&amp;#39;#sum-moon-icon&amp;#39;).addClass(&amp;quot;fa-sun&amp;quot;).removeClass(&amp;#39;fa-moon&amp;#39;)),

        setTimeout(function () &amp;#123;
          $(&amp;#39;.Cuteen_DarkSky&amp;#39;).fadeOut(1e3, function () &amp;#123;
            $(this).remove()
          &amp;#125;)
        &amp;#125;, 2e3)
      &amp;#125;)
  &amp;#125;
&amp;lt;&amp;#x2F;script&amp;gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;p&gt;再在 &lt;code&gt;themes&amp;gt;hexo-theme-matery&amp;gt;layout&amp;gt;layout.ejs&lt;/code&gt; 文件中引用一下&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;需要在 body 标签内部插入下面代码&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-ejs&#34; data-language=&#34;ejs&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-ejs&#34;&gt;&amp;lt;%- partial(&amp;#39;_widget&amp;#x2F;day-night.ejs&amp;#39;) %&amp;gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;h3 id=&#34;按钮样式&#34;&gt;按钮样式&lt;/h3&gt;
&lt;p&gt;完成上面操作以后，就需要添加按钮样式和切换动画了，同样是在 &lt;code&gt;themes&amp;gt;hexo-theme-matery&amp;gt;source&amp;gt;css&amp;gt;matery.css&lt;/code&gt; 中&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-css&#34; data-language=&#34;css&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-css&#34;&gt;&amp;#x2F;* 黑夜模式动画 *&amp;#x2F;
.Cuteen_DarkSky,
.Cuteen_DarkSky:before &amp;#123;
    content: &amp;#39;&amp;#39;;
    position: fixed;
    left: 0;
    right: 0;
    top: 0;
    bottom: 0;
    z-index: 8888;
&amp;#125;

.Cuteen_DarkSky &amp;#123;
    background: linear-gradient(#feb8b0, #fef9db);
&amp;#125;

.Cuteen_DarkSky:before &amp;#123;
    transition: 2s ease all;
    opacity: 0;
    background: linear-gradient(#4c3f6d, #6c62bb, #93b1ed);
&amp;#125;

.DarkMode .Cuteen_DarkSky:before &amp;#123;
    opacity: 1;
&amp;#125;

.Cuteen_DarkPlanet &amp;#123;
    z-index: 9999;
    position: fixed;
    left: -50%;
    top: -50%;
    width: 200%;
    height: 200%;
    -webkit-animation: CuteenPlanetMove 2s cubic-bezier(0.7, 0, 0, 1);
    animation: CuteenPlanetMove 2s cubic-bezier(0.7, 0, 0, 1);
    transform-origin: center bottom;
&amp;#125;

@-webkit-keyframes CuteenPlanetMove &amp;#123;
    0% &amp;#123;
        transform: rotate(0);
    &amp;#125;
    to &amp;#123;
        transform: rotate(360deg);
    &amp;#125;
&amp;#125;

@keyframes CuteenPlanetMove &amp;#123;
    0% &amp;#123;
        transform: rotate(0);
    &amp;#125;
    to &amp;#123;
        transform: rotate(360deg);
    &amp;#125;
&amp;#125;

.Cuteen_DarkPlanet:after &amp;#123;
    position: absolute;
    left: 35%;
    top: 40%;
    width: 9.375rem;
    height: 9.375rem;
    border-radius: 50%;
    content: &amp;#39;&amp;#39;;
    background: linear-gradient(#fefefe, #fffbe8);
&amp;#125;

&amp;#x2F;*黑夜模式按钮*&amp;#x2F;
.sum-moon-box &amp;#123;
    width: 48px;
    height: 48px;
    text-align: center;
    border-radius: 50%;
    position: fixed;
    right: 15px;
    bottom: 195px;
    margin-bottom: 0;
    z-index: 900;
&amp;#125;

.sum-moon-box .btn-floating &amp;#123;
    width: 48px;
    height: 48px;
&amp;#125;

.sum-moon-box i &amp;#123;
    font-size: 1.8rem;
    line-height: 48px !important;
&amp;#125;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;h3 id=&#34;定时提示切换黑夜模式&#34;&gt;定时提示切换黑夜模式&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;在 &lt;code&gt;themes&amp;gt;hexo-theme-matery&amp;gt;source&amp;gt;js&amp;gt;matery.js&lt;/code&gt; 中添加下列代码&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-javascript&#34; data-language=&#34;javascript&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-javascript&#34;&gt;&amp;#x2F;&amp;#x2F;黑夜模式提醒开启功能
setTimeout(function () &amp;#123;
    if ((new Date().getHours() &amp;gt;&amp;#x3D; 19 || new Date().getHours() &amp;lt; 7) &amp;amp;&amp;amp; !$(&amp;#39;body&amp;#39;).hasClass(&amp;#39;DarkMode&amp;#39;)) &amp;#123;
        let toastHTML &amp;#x3D; &amp;#39;&amp;lt;span style&amp;#x3D;&amp;quot;color:#97b8b2;border-radius: 10px;&amp;gt;&amp;#39; + &amp;#39;&amp;lt;i class&amp;#x3D;&amp;quot;fa fa-bellaria-hidden&amp;#x3D;&amp;quot;true&amp;quot;&amp;gt;&amp;lt;&amp;#x2F;i&amp;gt;晚上使用黑夜模式阅读能够减轻视觉疲劳。&amp;lt;&amp;#x2F;span&amp;gt;&amp;#39;
        M.toast(&amp;#123; html: toastHTML &amp;#125;)
    &amp;#125;
&amp;#125;, 2000)&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;h3 id=&#34;黑夜模式持久化&#34;&gt;黑夜模式持久化&lt;/h3&gt;
&lt;blockquote&gt;
&lt;p&gt;在 &lt;code&gt;themes&amp;gt;hexo-theme-matery&amp;gt;layout&amp;gt;layout.ejs&lt;/code&gt; 中添加下列代码（最好插入在 &lt;code&gt;&amp;lt;%- partial(&#39;_partial/day-night.ejs&#39;) %&amp;gt;&lt;/code&gt; 下面）&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-javascript&#34; data-language=&#34;javascript&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-javascript&#34;&gt;&amp;#x2F;* 模式判断 *&amp;#x2F;
&amp;lt;script&amp;gt;
    &amp;#x2F;* 模式判断 *&amp;#x2F;
    if (localStorage.getItem(&amp;#39;isDark&amp;#39;) &amp;#x3D;&amp;#x3D;&amp;#x3D; &amp;#39;1&amp;#39;) &amp;#123;
        document.body.classList.add(&amp;#39;DarkMode&amp;#39;);
        $(&amp;#39;#sum-moon-icon&amp;#39;).addClass(&amp;quot;fa-sun&amp;quot;).removeClass(&amp;#39;fa-moon&amp;#39;)
    &amp;#125; else &amp;#123;
        document.body.classList.remove(&amp;#39;DarkMode&amp;#39;);
        $(&amp;#39;#sum-moon-icon&amp;#39;).removeleClass(&amp;quot;fa-sun&amp;quot;).addClass(&amp;#39;fa-moon&amp;#39;)
    &amp;#125;
&amp;lt;&amp;#x2F;script&amp;gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;p&gt;完成以上操作就完成了基本的黑夜模式了。&lt;/p&gt;
&lt;h3 id=&#34;黑夜白天切换的动态背景&#34;&gt;黑夜白天切换的动态背景&lt;/h3&gt;
&lt;p&gt;下面这是黑夜白天切换的动态背景，在你新建的 &lt;strong&gt;day-night.ejs&lt;/strong&gt; 文件中加入下列代码&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-markup&#34; data-language=&#34;markup&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-markup&#34;&gt;&amp;lt;div class&amp;#x3D;&amp;quot;stars-con&amp;quot;&amp;gt;
  &amp;lt;div id&amp;#x3D;&amp;quot;stars&amp;quot;&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;
  &amp;lt;div id&amp;#x3D;&amp;quot;stars2&amp;quot;&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;
  &amp;lt;div id&amp;#x3D;&amp;quot;stars3&amp;quot;&amp;gt;&amp;lt;&amp;#x2F;div&amp;gt;  
&amp;lt;&amp;#x2F;div&amp;gt;&lt;/code&gt;&lt;/pre&gt;&lt;/div&gt;&lt;/figure&gt;
&lt;p&gt;在 &lt;code&gt;themes&amp;gt;hexo-theme-matery&amp;gt;source&amp;gt;css&amp;gt;matery.css&lt;/code&gt; 中加上下面的代码&lt;/p&gt;
&lt;figure&gt;&lt;div class=&#34;code-area&#34;&gt;&lt;pre class=&#34;line-numbers language-css&#34; data-language=&#34;css&#34; data-start=&#34;1&#34;&gt;&lt;code class=&#34;language-css&#34;&gt;&amp;#x2F;*黑夜模式背景*&amp;#x2F;
body.DarkMode &amp;#123;
    background: linear-gradient(#15151b, #1b1b2e, #231832) !important;
&amp;#125;

@keyframes animStar &amp;#123;
    from &amp;#123;
        transform: translateY(0)
    &amp;#125;
    to &amp;#123;
        transform: translateY(-2000px)
    &amp;#125;
&amp;#125;

body.DarkMode .stars-con &amp;#123;
    position: fixed;
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    z-index: -111;
    background: linear-gradient(#15151b, #1b1b2e, #231832);
&amp;#125;

body.DarkMode #stars &amp;#123;
    width: 1px;
