&lt;td&gt;&lt;a href=&#34;https://forum.gitlab.com/t/what-are-the-restrictions-for-gitlab-pages-sites/15067/6&#34;&gt;10GB&lt;/a&gt;&lt;/td&gt;
&lt;td&gt;&lt;a href=&#34;https://www.netlify.com/tos/#for-free-accounts&#34;&gt;100GB&lt;/a&gt;&lt;/td&gt;
&lt;td&gt;&lt;a href=&#34;https://vercel.com/docs/platform/limits#files&#34;&gt;12.5K Files&lt;/a&gt;&lt;/td&gt;
